public class LastDigitSum {
    public static int addLastDigits(int input1, int input2) {
        // Input: Two integer parameters

        // Process: Extract absolute last digits and add
        int digit1 = Math.abs(input1) % 10;
        int digit2 = Math.abs(input2) % 10;
        int result = digit1 + digit2;

        // Output: Return sum
        return result;
    }
}

public class MultipleChecker {
    public static int isMultiple(int num1, int num2) {
        // Input: Parameters num1 and num2
        if (num1 == 0 || num2 == 0) {
            return 3; // Output boundary case
        }

        // Process: Check divisibility
        if (num1 % num2 == 0) {
            return 2; // Output: Is multiple
        } else {
            return 1; // Output: Not multiple
        }
    }
}

public class StringCombiner {
    public static String combine(String a, String b) {
        // Input: Two strings a and b

        // Storage: Store lengths
        int l1 = a.length();
        int l2 = b.length();

        // Process: Determine shorter and concatenate
        String result;
        if (l1 < l2) {
            result = a + b + a;
        } else {
            result = b + a + b;
        }

        // Output: Return final combined string
        return result;
    }
}

