public class EvenOddCounter {
    public static int countMatches(int n1, int n2, int n3, int n4, int n5, String type) {
        // Input: 5 integer arguments and 1 type request string
        int[] numbers = {n1, n2, n3, n4, n5}; // Storage
        int count = 0; // Storage

        // Process: Loop and condition checks
        for (int num : numbers) {
            boolean isEven = (num % 2 == 0);
            if (type.equalsIgnoreCase("even") && isEven) {
                count++;
            } else if (type.equalsIgnoreCase("odd") && !isEven) {
                count++;
            }
        }

        // Output: Return final counter
        return count;
    }
}

