public class SecondLastDigit {
    public static int getSecondLast(int num) {
        // Input: One integer parameter
        int absVal = Math.abs(num); // Storage

        // Process: Check boundaries
        if (absVal < 10) {
            return -1; // Output: Single digit
        }

        // Process: Drop units and read last digit
        int result = (absVal / 10) % 10; // Storage

        // Output: Return result
        return result;
    }
}

