public class AlternateCombiner {
    public static String combine(String a, String b) {
        // Input: Strings a and b

        // Storage: StringBuilder to accumulate output
        StringBuilder sb = new StringBuilder();
        int i = 0;

        // Process: Loop characters alternately
        while (i < a.length() || i < b.length()) {
            if (i < a.length()) {
                sb.append(a.charAt(i));
            }
            if (i < b.length()) {
                sb.append(b.charAt(i));
            }
            i++;
        }

        // Output: Convert to String and return
        return sb.toString();
    }
}

public class Padovan {
    public static void printPadovan(int num) {
        // Input: 'num' representing terms to print

        // Storage: Initialize base states
        int p0 = 1, p1 = 1, p2 = 1;

        if (num >= 1) System.out.print(p0 + " ");
        if (num >= 2) System.out.print(p1 + " ");
        if (num >= 3) System.out.print(p2 + " ");

        // Process: Compute sequence terms iteratively
        for (int i = 3; i < num; i++) {
            int pNext = p0 + p1;
            System.out.print(pNext + " ");
            p0 = p1;
            p1 = p2;
            p2 = pNext;
        }
        System.out.println(); // Output boundary
    } 
}

