import java.util.ArrayList;
import java.util.Collections;

public class ArrayLeaders {
    public static ArrayList<Integer> findLeaders(int[] arr, int n) {
        // Storage: List to store leaders
        ArrayList<Integer> leadersList = new ArrayList<>();

        if (n == 0) return leadersList;

        // Process: Scan from right to left
        int currentMax = arr[n - 1];
        leadersList.add(currentMax); // Rightmost is always a leader

        for (int i = n - 2; i >= 0; i--) {
            if (arr[i] >= currentMax) { // Equal or greater
                currentMax = arr[i];
                leadersList.add(currentMax);
            }
        }

        // Process: Reverse to restore original order
        Collections.reverse(leadersList);

        // Output: Return list of leaders
        return leadersList;
    }
}

