public class NumberReversePower {
    public static long computePower(int N, int R) {
        // Input: N (number) and R (reversed digits)
        long MOD = 1000000007L; // Storage

        // Process: Binary exponentiation (O(log R))
        long result = 1;
        long base = N % MOD;
        long exp = R;

        while (exp > 0) {
            if (exp % 2 == 1) {
                result = (result * base) % MOD;
            }
            base = (base * base) % MOD;
            exp = exp / 2;
        }

        // Output: Return final modulo result
        return result;
    }
}

