public class RecursiveMean {
    public static double findMean(double[] arr, int n) {
        // Input: Double array and current count n

        // Process: Base recursion case
        if (n == 1) {
            return arr[0]; // Output: base
        }

        // Process: Recurse for n-1 and calculate current mean
        double subMean = findMean(arr, n - 1); // Storage
        double currentMean = (subMean * (n - 1) + arr[n - 1]) / n; // Storage

        // Output: Return calculated mean
        return currentMean;
    }
}

