public class PairSumCount {
    public static int getPairsCount(int[] arr, int n, int K) {
        // Input: Array, size n, and target sum K
        int pairCount = 0; // Storage

        // Process: Double loops search
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (arr[i] + arr[j] == K) {
                    pairCount++;
                }
            }
        }

        // Output: Return final pair counter
        return pairCount;
    }
}
